INSERT INTO academico.carrera (id, categoria_id, nombre, descripcion, perfil_egresado, imagen, sucursales, campo_laboral) VALUES (201, 2, 'Medicina Humana', 'Diagnostica y trata enfermedades para preservar y restaurar la salud humana con alto sentido ético.', 'Médico cirujano íntegro, con sólidas bases científicas y humanistas capacitado para atender problemas médicos complejos y liderar la prevención comunitaria.', 'https://images.unsplash.com/photo-1537368910025-700350fe46c7?auto=format&fit=crop&q=80&w=600', '{"Lima","Arequipa"}', '{"Médico en Hospitales Públicos y Clínicas Privadas","Investigador Científico y Académico de Medicina","Consultor en Políticas Públicas de Salud","Gestor y Administrador de Servicios Sanitarios"}');
