INSERT INTO academico.carrera (id, categoria_id, nombre, descripcion, perfil_egresado, imagen, sucursales, campo_laboral) VALUES (204, 2, 'Odontología', 'Previene, diagnostica y trata problemas de salud bucodental mejorando la calidad de vida de los pacientes.', 'El egresado cuenta con alta destreza clínica y tecnológica para realizar tratamientos de restauración, cirugía oral y ortodoncia con enfoque estético y funcional.', 'https://images.unsplash.com/photo-1588776814546-1ffcf47267a5?auto=format&fit=crop&q=80&w=600', '{"Lima","Arequipa"}', '{"Cirujano Dentista en Clínicas Dentales Privadas","Odontólogo en el Sector de Salud Pública (MINSA, EsSalud)","Especialista en Ortodoncia, Periodoncia o Endodoncia","Asesor de Equipamiento e Insumos Odontológicos"}');
